394→    public static void openPost(Context context, ReaderPost post) {
395→        String url = post.getUrl();
396→        if (WPUrlUtils.isWordPressCom(url) || (post.isWP() && !post.isJetpack)) {
397→            WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(context, url);
398→        } else {
399→            WPWebViewActivity.openURL(context, url, ReaderConstants.HTTP_REFERER_URL);
400→        }
401→    }
402→
403→    public static void sharePost(Context context, ReaderPost post) throws ActivityNotFoundException {
404→        String url = (post.hasShortUrl() ? post.getShortUrl() : post.getUrl());
405→
406→        Intent intent = new Intent(Intent.ACTION_SEND);
407→        intent.setType("text/plain");
408→        intent.putExtra(Intent.EXTRA_TEXT, url);
409→        intent.putExtra(Intent.EXTRA_SUBJECT, post.getTitle());
410→
411→        context.startActivity(Intent.createChooser(intent, context.getString(R.string.share_link)));
412→    }
413→
414→    public static void openUrl(Context context, String url, OpenUrlType openUrlType) {
415→        if (context == null || TextUtils.isEmpty(url)) {
416→            return;
417→        }
418→
419→        if (openUrlType == OpenUrlType.INTERNAL) {
420→            openUrlInternal(context, url);
421→        } else {
422→            ActivityLauncher.openUrlExternal(context, url);
423→        }
424→    }
425→
426→    /*
427→     * open the passed url in the app's internal WebView activity
428→     */
429→    private static void openUrlInternal(Context context, @NonNull String url) {
430→        // That won't work on wpcom sites with custom urls
431→        if (WPUrlUtils.isWordPressCom(url)) {
432→            WPWebViewActivity.openUrlByUsingGlobalWPCOMCredentials(context, url);
433→        } else {
434→            WPWebViewActivity.openURL(context, url, ReaderConstants.HTTP_REFERER_URL);
435→        }
436→    }
437→}
