24→/**
25→ * service which updates posts with specific tags or in specific blogs/feeds - relies on
26→ * EventBus to alert of update status
27→ */
28→
29→public class ReaderPostJobService extends JobService implements ServiceCompletionListener {
30→    private ReaderPostLogic mReaderPostLogic;
31→
32→    @Override public boolean onStartJob(JobParameters params) {
33→        AppLog.i(AppLog.T.READER, "reader post job service > started");
34→        UpdateAction action;
35→        if (params.getExtras() != null) {
36→            if (params.getExtras().containsKey(ARG_ACTION)) {
37→                action = UpdateAction.values()[(Integer) params.getExtras().get(ARG_ACTION)];
38→            } else {
39→                action = UpdateAction.REQUEST_NEWER;
40→            }
41→
42→
43→            if (params.getExtras().containsKey(ARG_TAG_PARAM_SLUG)) {
44→                ReaderTag tag = getReaderTagFromBundleParams(params.getExtras());
45→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action, tag));
46→                mReaderPostLogic.performTask(params, action, tag, -1, -1);
47→            } else if (params.getExtras().containsKey(ARG_BLOG_ID)) {
48→                long blogId = params.getExtras().getLong(ARG_BLOG_ID, 0);
49→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
50→                mReaderPostLogic.performTask(params, action, null, blogId, -1);
51→            } else if (params.getExtras().containsKey(ARG_FEED_ID)) {
52→                long feedId = params.getExtras().getLong(ARG_FEED_ID, 0);
53→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
54→                mReaderPostLogic.performTask(params, action, null, -1, feedId);
55→            }
56→        }
57→        return true;
58→    }
59→
60→    @Override public boolean onStopJob(JobParameters params) {
61→        AppLog.i(AppLog.T.READER, "reader post job service > stopped");
62→        jobFinished(params, false);
63→        return false;
64→    }
65→
66→    @Override
67→    public void onCreate() {
68→        super.onCreate();
69→        mReaderPostLogic = new ReaderPostLogic(this);
70→        AppLog.i(AppLog.T.READER, "reader post job service > created");
71→    }
72→
73→    @Override
74→    public void onDestroy() {
75→        AppLog.i(AppLog.T.READER, "reader post job service > destroyed");
76→        super.onDestroy();
77→    }
78→
79→    @Override
80→    public void onCompleted(Object companion) {
81→        AppLog.i(AppLog.T.READER, "reader post job service > all tasks completed");
82→        jobFinished((JobParameters) companion, false);
83→    }
84→
85→    private ReaderTag getReaderTagFromBundleParams(PersistableBundle bundle) {
86→        String slug = bundle.getString(ARG_TAG_PARAM_SLUG);
87→        String displayName = bundle.getString(ARG_TAG_PARAM_DISPLAY_NAME);
88→        String title = bundle.getString(ARG_TAG_PARAM_TITLE);
89→        String endpoint = bundle.getString(ARG_TAG_PARAM_ENDPOINT);
90→        int tagType = bundle.getInt(ARG_TAG_PARAM_TAGTYPE);
91→        ReaderTag tag = new ReaderTag(slug, displayName, title, endpoint, ReaderTagType.fromInt(tagType));
92→        return tag;
93→    }
94→}
