 268→    /*
 269→     * purge excess posts in the passed tag
 270→     */
 271→    private static final int MAX_POSTS_PER_TAG = ReaderConstants.READER_MAX_POSTS_TO_DISPLAY;
 272→
 273→    private static int purgePostsForTag(SQLiteDatabase db, ReaderTag tag) {
 274→        int numPosts = getNumPostsWithTag(tag);
 275→        if (numPosts <= MAX_POSTS_PER_TAG) {
 276→            return 0;
 277→        }
 278→        String tagName = tag.getTagSlug();
 279→        String tagType = Integer.toString(tag.tagType.toInt());
 280→        String[] args = {tagName, tagType, tagName, tagType, Integer.toString(MAX_POSTS_PER_TAG)};
 281→        String where = "tag_name=? AND tag_type=? AND pseudo_id NOT IN (SELECT DISTINCT pseudo_id FROM tbl_posts WHERE "
 282→                       + "tag_name=? AND tag_type=? ORDER BY " + getSortColumnForTag(tag) + " DESC LIMIT ?)";
 283→        int numDeleted = db.delete("tbl_posts", where, args);
 284→        AppLog.d(AppLog.T.READER,
 285→                String.format(Locale.ENGLISH, "reader post table > purged %d posts in tag %s", numDeleted,
 286→                        tag.getTagNameForLog()));
 287→        return numDeleted;
 288→    }
