2383→    private void setIsUpdating(boolean isUpdating, UpdateAction updateAction) {
2384→        if (!isAdded() || mIsUpdating == isUpdating) {
2385→            return;
2386→        }
2387→
2388→        if (updateAction == UpdateAction.REQUEST_OLDER) {
2389→            // show/hide progress bar at bottom if these are older posts
2390→            showLoadingProgress(isUpdating);
2391→        } else if (isUpdating) {
2392→            // show swipe-to-refresh if update started
2393→            mRecyclerView.setRefreshing(true);
2394→        } else {
2395→            // hide swipe-to-refresh progress if update is complete
2396→            mRecyclerView.setRefreshing(false);
2397→        }
2398→        mIsUpdating = isUpdating;
2399→
2400→        // if swipe-to-refresh isn't active, keep it disabled during an update - this prevents
2401→        // doing a refresh while another update is already in progress
2402→        if (mRecyclerView != null && !mRecyclerView.isRefreshing()) {
2403→            mRecyclerView.setSwipeToRefreshEnabled(!isUpdating && isSwipeToRefreshSupported());
2404→        }
