29→public class ReaderPostJobService extends JobService implements ServiceCompletionListener {
30→    private ReaderPostLogic mReaderPostLogic;
31→
32→    @Override public boolean onStartJob(JobParameters params) {
33→        AppLog.i(AppLog.T.READER, "reader post job service > started");
34→        UpdateAction action;
35→        if (params.getExtras() != null) {
36→            if (params.getExtras().containsKey(ARG_ACTION)) {
37→                action = UpdateAction.values()[(Integer) params.getExtras().get(ARG_ACTION)];
38→            } else {
39→                action = UpdateAction.REQUEST_NEWER;
40→            }
41→
42→
43→            if (params.getExtras().containsKey(ARG_TAG_PARAM_SLUG)) {
44→                ReaderTag tag = getReaderTagFromBundleParams(params.getExtras());
45→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action, tag));
46→                mReaderPostLogic.performTask(params, action, tag, -1, -1);
47→            } else if (params.getExtras().containsKey(ARG_BLOG_ID)) {
48→                long blogId = params.getExtras().getLong(ARG_BLOG_ID, 0);
49→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
50→                mReaderPostLogic.performTask(params, action, null, blogId, -1);
51→            } else if (params.getExtras().containsKey(ARG_FEED_ID)) {
52→                long feedId = params.getExtras().getLong(ARG_FEED_ID, 0);
53→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsStarted(action));
54→                mReaderPostLogic.performTask(params, action, null, -1, feedId);
55→            }
56→        }
57→        return true;
58→    }
