68→        super.onCreate();
69→        mReaderPostLogic = new ReaderPostLogic(this);
70→        AppLog.i(AppLog.T.READER, "reader post job service > created");
71→    }
72→
73→    @Override
74→    public void onDestroy() {
75→        AppLog.i(AppLog.T.READER, "reader post job service > destroyed");
76→        super.onDestroy();
77→    }
