 56→        requestPostsWithTag(
 57→                tag,
 58→                action,
 59→                new ReaderActions.UpdateResultListener() {
 60→                    @Override
 61→                    public void onUpdateResult(ReaderActions.UpdateResult result) {
 62→                        EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(tag, result, action));
 63→                        mCompletionListener.onCompleted(mListenerCompanion);
 64→                    }
 65→                });
 66→    }
