1276→    /**
1277→     * Currently "is_bookmarked" field is not supported by the server, therefore posts from the server have always
1278→     * is_bookmarked set to false. This method is a workaround which makes sure, that the field is always up to date
1279→     * and synced across all instances(rows) of each post.
1280→     */
1281→    private static void updateIsBookmarkedField(final ReaderPostList posts) {
1282→        ReaderBlogIdPostIdList bookmarkedPosts = getBookmarkedPostIds();
1283→        for (ReaderPost post : posts) {
1284→            for (ReaderBlogIdPostId bookmarkedPostId : bookmarkedPosts) {
1285→                if (isBookmarkedPost(post, bookmarkedPostId)) post.isBookmarked = true;
1286→            }
1287→        }
1288→    }
