1294→    public static void updateBookmarkedPostPseudoId(final ReaderPostList posts) {
1295→        ReaderBlogIdPostIdList bookmarkedPosts = getBookmarkedPostIds();
1296→        for (ReaderPost post : posts) {
1297→            for (ReaderBlogIdPostId bookmarkedPostId : bookmarkedPosts) {
1298→                if (isBookmarkedPost(post, bookmarkedPostId)) updateBookmarkedPostPseudoId(post, bookmarkedPostId);
1299→            }
1300→        }
1301→    }
