1303→    public static void updateBookmarkedPostPseudoId(ReaderPost post, ReaderBlogIdPostId bookmarkedPostIds) {
1304→        ReaderPost bookmarkedPost = getBlogPost(bookmarkedPostIds.getBlogId(), bookmarkedPostIds.getPostId(), true);
1305→        if (bookmarkedPost != null && !bookmarkedPost.getPseudoId().equals(post.getPseudoId())) {
1306→            SQLiteDatabase db = ReaderDatabase.getWritableDb();
1307→            db.beginTransaction();
1308→            try {
1309→                String sql = "UPDATE tbl_posts SET pseudo_id=? WHERE blog_id=? AND post_id=? AND tag_type=?";
1310→                db.execSQL(sql, new String[]{
1311→                        post.getPseudoId(),
1312→                        Long.toString(post.blogId),
1313→                        Long.toString(post.postId),
1314→                        Integer.toString(ReaderTagType.BOOKMARKED.toInt())});
1315→                db.setTransactionSuccessful();
1316→            } finally {
1317→                db.endTransaction();
1318→            }
1319→        }
1320→    }
